class Solution:
    def canJump(self, nums):
        n = len(nums)
        dp = [False] * n
        dp[0] = True
        for i in range(n):
            if not dp[i]:
                continue
            far = min(n - 1, i + nums[i])
            for j in range(i + 1, far + 1):
                dp[j] = True
        return dp[n - 1]

